import React from 'react';

const OurStory: React.FC = () => {
    return (
        <div className="home-page">
            <h1>Meet Andrew — Your Local Upholstery Expert</h1>
            <img src="/images/Our_Story.jpg" alt="Andrew, the upholstery expert" className="profile-image" />
            <p>Hi, I am Andrew, the owner and sole technician at RTP Upholstery, bringing hands-on expertise and a personal 
touch to every job. Based in Morrisville, NC, he serves homeowners, renters, and property managers 
throughout the Research Triangle Park region.
Andrew takes pride in transparent pricing, quality results, and treating every customer’s home with care 
and respect. When you book with RTP Upholstery, you’re working directly with Andrew — not a 
franchise or call center.
Every appointment is handled with the same attention to detail, whether it’s a quick chair clean or a full 
move-out service. Andrew’s goal is simple: leave your furniture looking better than you thought 
possible</p>
        </div>
    );
};

export default OurStory;
